use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type VaultDatum {
  owner: ByteArray,
  min_tokens: Int,
}

fn has_min_tokens(outputs: List<Output>, policy_id: ByteArray, min_tokens: Int) -> Bool {
  list.any(
    outputs,
    fn(output) {
      let total =
        assets.tokens(output.value, policy_id)
          |> dict_sum()
      total >= min_tokens
    },
  )
}

fn dict_sum(d: aiken/collection/dict.Dict<ByteArray, Int>) -> Int {
  use aiken/collection/dict
  dict.foldl(d, 0, fn(_k, v, acc) { acc + v })
}

validator parametric_vault(policy_id: ByteArray) {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let owner_signed = list.has(self.extra_signatories, d.owner)
    let tokens_present = has_min_tokens(self.outputs, policy_id, d.min_tokens)
    owner_signed && tokens_present
  }
}
